// Determine which edition this run produces + carry run metadata downstream.
const now = new Date();
const hour = now.getHours();

let edition = 'Morning';
if (hour >= 11 && hour < 17) edition = 'Afternoon';
else if (hour >= 17) edition = 'Evening';

const dateStr = now.toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

// ====== CONFIGURE THESE ======
const recipients = 'recipient@example.com';                    // comma-separated allowed
const adminEmail = 'admin@example.com';                        // failure alerts go here
const fromEmail  = 'AI Daily Newsletter <newsletter@example.com>';
// =============================

return [{
  json: { runTimestamp: now.toISOString(), edition, dateStr, hour, recipients, adminEmail, fromEmail }
}];

// Flatten every collected source into one normalized, deduped article list.
const cfg = $('Set Run Config').first().json;
const incoming = $input.all();
const articles = [];

const push = (a) => {
  if (!a || !a.title) return;
  articles.push({
    title: String(a.title).trim(),
    summary: String(a.summary || '').trim().slice(0, 600),
    url: a.url || '',
    source: a.source || 'News',
    publishedAt: a.publishedAt || ''
  });
};

for (const item of incoming) {
  const j = item.json || {};

  // Hacker News (Algolia) -> { hits: [...] }
  if (Array.isArray(j.hits)) {
    for (const h of j.hits) push({
      title: h.title || h.story_title,
      summary: 'Hacker News front page \u2022 ' + (h.points || 0) + ' pts, ' + (h.num_comments || 0) + ' comments',
      url: h.url || h.story_url || ('https://news.ycombinator.com/item?id=' + h.objectID),
      source: 'Hacker News',
      publishedAt: h.created_at || ''
    });
    continue;
  }

  // Reddit -> { data: { children: [ { data: {...} } ] } }
  if (j.data && Array.isArray(j.data.children)) {
    for (const c of j.data.children) {
      const d = c.data || {};
      push({
        title: d.title,
        summary: 'r/' + (d.subreddit || 'popular') + ' \u2022 ' + (d.ups || 0) + ' upvotes',
        url: d.url_overridden_by_dest || d.url || ('https://reddit.com' + (d.permalink || '')),
        source: 'Reddit',
        publishedAt: d.created_utc ? new Date(d.created_utc * 1000).toISOString() : ''
      });
    }
    continue;
  }

  // RSS Feed Read -> one item per article
  if (j.title) push({
    title: j.title,
    summary: j.contentSnippet || j.content || j.summary || '',
    url: j.link || j.url || '',
    source: j.creator || 'News RSS',
    publishedAt: j.isoDate || j.pubDate || ''
  });
}

// Dedupe by normalized title
const seen = new Set();
const deduped = [];
for (const a of articles) {
  const key = a.title.toLowerCase().replace(/[^a-z0-9]+/g, ' ').trim().slice(0, 80);
  if (key && !seen.has(key)) { seen.add(key); deduped.push(a); }
}

const capped = deduped.slice(0, 70);                       // keep prompt within budget
const sourcesUsed = [...new Set(capped.map(a => a.source))];

return [{
  json: {
    config: cfg,
    runTimestamp: cfg.runTimestamp,
    dateStr: cfg.dateStr,
    edition: cfg.edition,
    articleCount: capped.length,
    sourcesUsed,
    articles: capped
  }
}];

// Build a responsive, mobile-friendly HTML email + plain-text fallback.
const cfg  = $('Set Run Config').first().json;
const prep = $('Normalize & Prepare').first().json;

// Agent structured output (defensive: object, {output}, or JSON string)
let nl = ($json.output !== undefined) ? $json.output : $json;
if (typeof nl === 'string') {
  try { nl = JSON.parse(nl); }
  catch (e) { const m = nl.match(/\{[\s\S]*\}/); nl = m ? JSON.parse(m[0]) : {}; }
}
nl = nl || {};

const safe = (v) => (v == null ? '' : String(v));
const arr  = (v) => (Array.isArray(v) ? v : []);
const topStories = arr(nl.topStories);
const aiTech     = arr(nl.aiTech);
const business   = arr(nl.business);
const global     = arr(nl.global);
const viral      = arr(nl.viral);
const quick      = arr(nl.quickSummary);

const subject = '[AI Daily Newsletter] - ' + cfg.dateStr + ' - ' + cfg.edition + ' Edition';

const card = (s, accent) => `
  <tr><td style="padding:14px 0;border-bottom:1px solid #ececf1;">
    <h3 style="margin:0 0 6px;font-size:17px;line-height:1.3;color:#16161a;">${safe(s.headline)}</h3>
    <p style="margin:0 0 8px;font-size:14px;line-height:1.6;color:#3f3f46;">${safe(s.summary)}</p>
    ${s.whyItMatters ? `<div style="background:${accent}1a;border-left:3px solid ${accent};padding:8px 12px;border-radius:4px;font-size:13px;color:#27272a;"><strong>Why it matters:</strong> ${safe(s.whyItMatters)}</div>` : ''}
    ${s.url ? `<a href="${safe(s.url)}" style="display:inline-block;margin-top:8px;font-size:12px;color:#6d28d9;text-decoration:none;">Read more &rarr;</a>` : ''}
    ${s.source ? `<span style="font-size:11px;color:#a1a1aa;margin-left:8px;">${safe(s.source)}</span>` : ''}
  </td></tr>`;

const section = (icon, title, items, accent) => {
  if (!items.length) return '';
  return `
  <tr><td style="padding:22px 28px 0;">
    <h2 style="margin:0 0 4px;font-size:20px;color:${accent};">${icon} ${title}</h2>
    <table role="presentation" width="100%" cellpadding="0" cellspacing="0">${items.map(s => card(s, accent)).join('')}</table>
  </td></tr>`;
};

const quickList = quick.length ? `
  <tr><td style="padding:22px 28px;">
    <div style="background:#0f172a;border-radius:10px;padding:18px 22px;">
      <h2 style="margin:0 0 10px;font-size:18px;color:#fbbf24;">&#9889; Quick Summary &mdash; Top Insights</h2>
      <ol style="margin:0;padding-left:20px;color:#e2e8f0;font-size:14px;line-height:1.9;">${quick.map(q => `<li>${safe(q)}</li>`).join('')}</ol>
    </div>
  </td></tr>` : '';

const genTime = new Date(cfg.runTimestamp).toLocaleTimeString('en-US');

const html = `<!DOCTYPE html>
<html lang="en"><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${subject}</title></head>
<body style="margin:0;padding:0;background:#f4f4f7;font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Helvetica,Arial,sans-serif;">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f4f4f7;padding:24px 12px;">
<tr><td align="center">
<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="max-width:640px;background:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.06);">
  <tr><td style="background:linear-gradient(135deg,#6d28d9,#2563eb);padding:32px 28px;">
    <p style="margin:0;font-size:12px;letter-spacing:2px;text-transform:uppercase;color:#ddd6fe;">AI Daily Newsletter</p>
    <h1 style="margin:6px 0 0;font-size:26px;color:#ffffff;">${cfg.edition} Edition</h1>
    <p style="margin:6px 0 0;font-size:13px;color:#e0e7ff;">${cfg.dateStr}</p>
  </td></tr>
  ${section('&#128293;', 'Top Trending Stories', topStories, '#dc2626')}
  ${section('&#129302;', 'AI &amp; Technology Updates', aiTech, '#7c3aed')}
  ${section('&#128188;', 'Business &amp; Startup News', business, '#0891b2')}
  ${section('&#127758;', 'Global Events', global, '#059669')}
  ${section('&#128640;', 'Viral Trends &amp; Social Media', viral, '#ea580c')}
  ${quickList}
  <tr><td style="padding:24px 28px;background:#fafafa;border-top:1px solid #ececf1;">
    <p style="margin:0;font-size:12px;color:#a1a1aa;line-height:1.6;">
      Generated automatically by your n8n AI Newsletter pipeline.<br>
      ${prep.articleCount} articles analyzed from ${prep.sourcesUsed.length} sources &middot; ${cfg.dateStr} &middot; Generated at ${genTime}<br>
      Sources: ${prep.sourcesUsed.join(', ')}
    </p>
  </td></tr>
</table>
</td></tr></table></body></html>`;

const txtSection = (title, items) => items.length
  ? '\n' + title + '\n' + items.map(s => '- ' + safe(s.headline) + '\n  ' + safe(s.summary)
      + (s.whyItMatters ? '\n  Why it matters: ' + safe(s.whyItMatters) : '')
      + (s.url ? '\n  ' + safe(s.url) : '')).join('\n') + '\n'
  : '';

const text = [
  'AI DAILY NEWSLETTER - ' + cfg.edition + ' Edition',
  cfg.dateStr,
  '====================================',
  txtSection('TOP TRENDING STORIES', topStories),
  txtSection('AI & TECHNOLOGY UPDATES', aiTech),
  txtSection('BUSINESS & STARTUP NEWS', business),
  txtSection('GLOBAL EVENTS', global),
  txtSection('VIRAL TRENDS & SOCIAL MEDIA', viral),
  quick.length ? '\nQUICK SUMMARY\n' + quick.map((q,i)=>(i+1)+'. '+safe(q)).join('\n') : '',
  '\n--\nGenerated by n8n AI Newsletter - ' + prep.articleCount + ' articles from ' + prep.sourcesUsed.length + ' sources'
].join('\n');

return [{
  json: {
    subject, html, text,
    edition: cfg.edition, dateStr: cfg.dateStr, runTimestamp: cfg.runTimestamp,
    recipients: cfg.recipients, adminEmail: cfg.adminEmail, fromEmail: cfg.fromEmail,
    articleCount: prep.articleCount, sourcesUsed: prep.sourcesUsed,
    newsletterJson: nl, status: 'pending'
  }
}];
